# Bulk insert data into a table.
# -- Before running the script, create the table and insert data.
#CREATE TABLE [dbo].[bulkinsert] (Table nvarchar(150), Data nvarchar(max))
#INSERT INTO [dbo].[bulkinsert] (Table, Data) VALUES (N'Test1', N'1,2,3')
# -- Then clean up the table
#DROP TABLE [dbo].[bulkinsert]

function SqlBuild-BulkInsertTable {
    param ( [string]$ConnectionString, [string]$With = $null)
    $conn = New-Object System.Data.SQLClient.SQLConnection
    $conn.ConnectionString = $ConnectionString
    $handler = [System.Data.SqlClient.SqlInfoMessageEventHandler] {param($sender, $event) Write-Host $event.Message };
    $conn.add_InfoMessage($handler); 
    $conn.FireInfoMessageEventOnUserErrors = $true;
    $conn.Open()
    $command = $conn.CreateCommand()
    $command.CommandText = "if ((select value_in_use from sys.configurations where name = 'clr enabled') = 0)
begin
    Exec sp_configure 'show advanced options', 1; RECONFIGURE; exec sp_configure 'clr enabled', 1; RECONFIGURE; EXEC sp_configure 'show advanced options', 0; RECONFIGURE;
end

declare @hash varbinary(64) = CONVERT(varbinary(64), 'A1FAC54C96DFAC49723984E940007F06113BD1253F449BB4E76682DC2D3F39714372AEB6D60F399E467BA3E77B551F01111EEEE65DC99BB2FCD895EACB425FDD', 2);
exec sp_add_trusted_assembly @hash, N'sqlbuildbulkinserttable, version=0.0.0.0, culture=neutral, publickeytoken=null, processorarchitecture=msil';
create assembly [sqlbuild.bulkinserttable] authorization [dbo] from 
with permission_set = unsafe;
execute sp_executesql N'create procedure BulkInsertTable(@withopt nvarchar(2000)) as external name [sqlbuild.bulkinserttable].[SQLBuild.Functions].BulkInsertTable'
exec BulkInsertTable @withopt

BEGIN TRY exec sp_drop_trusted_assembly @hash END TRY BEGIN CATCH END CATCH
BEGIN TRY drop procedure BulkInsertTable END TRY BEGIN CATCH END CATCH
BEGIN TRY drop assembly [sqlbuild.bulkinserttable] END TRY BEGIN CATCH END CATCH"
    $withParam = New-Object System.Data.SQLClient.SqlParameter "@withopt", $With
    $command.Parameters.Add($withParam) > $null
    $command.CommandType = [System.Data.CommandType]::Text
    $command.ExecuteNonQuery() > $null
    $conn.Close()
}
